module.render:
    const val = args.value || '0';
    const label = args.label || '';
    const color = args.color || 'var(--accent-color)';
    const align = args.align || 'center';
    const valueSize = (args.valueSize && String(args.valueSize).trim()) || '5em';
    const bg = args.background && String(args.background).trim();
    const trend = (args.trend && args.trend !== 'none') ? args.trend : '';
    const trendHtml = trend ? `<span class="mdp-metrics-trend mdp-trend-${trend}">${trend === 'up' ? '▲' : '▼'}</span>` : '';
    const contentStr = sections[0] ? sections[0].trim() : '';
    let vars = `--met-color: ${color}; --met-align: ${align}; --met-size: ${valueSize};`;
    if (bg) vars += ` --met-bg: ${bg};`;
    return `\n\n
<div class="mdp-mod-metrics" style="${vars}">
  <div class="mdp-metrics-value">${val}${trendHtml}</div>
  ${label ? `<div class="mdp-metrics-label">${label}</div>` : ''}
  ${contentStr ? `<div class="mdp-metrics-desc">\n\n${contentStr}\n\n</div>` : ''}
</div>
\n\n`;
